from __future__ import annotations

from dataclasses import dataclass
from pathlib import Path
from typing import Literal

from lit.storage import read_json, write_json

OperationKind = Literal["merge", "rebase"]


@dataclass(frozen=True)
class MergeState:
    head_ref: str
    base_commit: str
    current_commit: str
    target_commit: str
    target_ref: str | None = None
    conflicts: tuple[str, ...] = ()

    def to_dict(self) -> dict[str, object]:
        data: dict[str, object] = {
            "base_commit": self.base_commit,
            "conflicts": list(self.conflicts),
            "current_commit": self.current_commit,
            "head_ref": self.head_ref,
            "target_commit": self.target_commit,
        }
        if self.target_ref is not None:
            data["target_ref"] = self.target_ref
        return data

    @classmethod
    def from_dict(cls, data: dict[str, object]) -> "MergeState":
        return cls(
            head_ref=str(data["head_ref"]),
            base_commit=str(data["base_commit"]),
            current_commit=str(data["current_commit"]),
            target_commit=str(data["target_commit"]),
            target_ref=(
                None if data.get("target_ref") is None else str(data["target_ref"])
            ),
            conflicts=tuple(str(path) for path in data.get("conflicts", [])),
        )


@dataclass(frozen=True)
class RebaseState:
    head_ref: str
    original_head: str
    onto: str
    pending_commits: tuple[str, ...] = ()
    applied_commits: tuple[str, ...] = ()
    current_commit: str | None = None
    conflicts: tuple[str, ...] = ()

    def to_dict(self) -> dict[str, object]:
        data: dict[str, object] = {
            "applied_commits": list(self.applied_commits),
            "conflicts": list(self.conflicts),
            "head_ref": self.head_ref,
            "onto": self.onto,
            "original_head": self.original_head,
            "pending_commits": list(self.pending_commits),
        }
        if self.current_commit is not None:
            data["current_commit"] = self.current_commit
        return data

    @classmethod
    def from_dict(cls, data: dict[str, object]) -> "RebaseState":
        return cls(
            head_ref=str(data["head_ref"]),
            original_head=str(data["original_head"]),
            onto=str(data["onto"]),
            pending_commits=tuple(str(commit) for commit in data.get("pending_commits", [])),
            applied_commits=tuple(str(commit) for commit in data.get("applied_commits", [])),
            current_commit=(
                None if data.get("current_commit") is None else str(data["current_commit"])
            ),
            conflicts=tuple(str(path) for path in data.get("conflicts", [])),
        )


@dataclass(frozen=True)
class OperationState:
    kind: OperationKind
    state: MergeState | RebaseState


def read_merge_state(path: Path) -> MergeState | None:
    data = read_json(path, default=None)
    if data is None:
        return None
    return MergeState.from_dict(data)


def write_merge_state(path: Path, state: MergeState | None) -> None:
    write_json(path, None if state is None else state.to_dict())


def read_rebase_state(path: Path) -> RebaseState | None:
    data = read_json(path, default=None)
    if data is None:
        return None
    return RebaseState.from_dict(data)


def write_rebase_state(path: Path, state: RebaseState | None) -> None:
    write_json(path, None if state is None else state.to_dict())


def active_operation(
    merge_state: MergeState | None,
    rebase_state: RebaseState | None,
) -> OperationState | None:
    if merge_state is not None and rebase_state is not None:
        raise RuntimeError("multiple operations are in progress")
    if merge_state is not None:
        return OperationState(kind="merge", state=merge_state)
    if rebase_state is not None:
        return OperationState(kind="rebase", state=rebase_state)
    return None

from __future__ import annotations

from dataclasses import dataclass
from pathlib import Path
from typing import Mapping

from lit.commits import CommitRecord, serialize_commit
from lit.index import IndexState
from lit.refs import branch_ref
from lit.repository import Repository, TrackedFile


@dataclass(frozen=True)
class MergeResult:
    status: str
    message: str
    commit_id: str | None = None
    conflicts: tuple[str, ...] = ()


def merge_revision(repository: Repository, revision: str) -> MergeResult:
    _ensure_operation_ready(repository)
    current_commit = repository.current_commit_id()
    if current_commit is None:
        raise ValueError("merge requires at least one commit on the current branch")

    target_commit = repository.resolve_revision(revision)
    if target_commit is None:
        raise ValueError(f"unknown revision: {revision}")

    if target_commit == current_commit:
        return MergeResult(status="noop", message="Already up to date.")

    base_commit = repository.merge_base(current_commit, target_commit)
    if base_commit == target_commit:
        return MergeResult(status="noop", message="Already up to date.")

    target_ref = _resolve_target_ref(repository, revision)
    if base_commit == current_commit:
        repository.write_branch(_current_branch(repository), target_commit)
        repository.apply_commit(target_commit, baseline_commit=current_commit)
        repository.clear_merge()
        return MergeResult(
            status="fast_forward",
            message=f"Fast-forwarded to {target_commit[:12]}.",
            commit_id=target_commit,
        )

    base_tree = repository.read_commit_tree(base_commit)
    current_tree = repository.read_commit_tree(current_commit)
    target_tree = repository.read_commit_tree(target_commit)
    plan = _merge_trees(repository, base_tree, current_tree, target_tree)

    repository.apply_tree(plan.files, baseline=current_tree)
    if plan.conflicts:
        _write_conflicts(repository, plan.conflicts)
        repository.begin_merge(
            base_commit=base_commit or "",
            current_commit=current_commit,
            target_commit=target_commit,
            target_ref=target_ref,
            conflicts=plan.conflict_paths,
        )
        return MergeResult(
            status="conflict",
            message="Merge stopped with conflicts.",
            conflicts=plan.conflict_paths,
        )

    commit_id = _write_commit(
        repository,
        tree=plan.files,
        parents=(current_commit, target_commit),
        message=f"Merge {revision} into {_current_branch(repository)}",
    )
    repository.apply_commit(commit_id, baseline_commit=current_commit)
    repository.clear_merge()
    return MergeResult(
        status="merged",
        message=f"Merge commit created: {commit_id[:12]}",
        commit_id=commit_id,
    )


@dataclass(frozen=True)
class ConflictFile:
    path: str
    content: str


@dataclass(frozen=True)
class MergePlan:
    files: dict[str, TrackedFile]
    conflicts: tuple[ConflictFile, ...]

    @property
    def conflict_paths(self) -> tuple[str, ...]:
        return tuple(conflict.path for conflict in self.conflicts)


def _merge_trees(
    repository: Repository,
    base_tree: Mapping[str, TrackedFile],
    current_tree: Mapping[str, TrackedFile],
    target_tree: Mapping[str, TrackedFile],
) -> MergePlan:
    merged: dict[str, TrackedFile] = {}
    conflicts: list[ConflictFile] = []
    for path in sorted(set(base_tree) | set(current_tree) | set(target_tree)):
        base_file = base_tree.get(path)
        current_file = current_tree.get(path)
        target_file = target_tree.get(path)
        resolved = _resolve_path(repository, base_file, current_file, target_file)
        if isinstance(resolved, ConflictFile):
            conflicts.append(resolved)
            continue
        if resolved is not None:
            merged[path] = resolved
    return MergePlan(files=merged, conflicts=tuple(conflicts))


def _resolve_path(
    repository: Repository,
    base_file: TrackedFile | None,
    current_file: TrackedFile | None,
    target_file: TrackedFile | None,
) -> TrackedFile | ConflictFile | None:
    if _same_file(current_file, target_file):
        return current_file
    if _same_file(base_file, current_file):
        return target_file
    if _same_file(base_file, target_file):
        return current_file

    path = (current_file or target_file or base_file)
    if path is None:
        return None
    return ConflictFile(
        path=path.path,
        content=_render_conflict(repository, base_file, current_file, target_file),
    )


def _same_file(left: TrackedFile | None, right: TrackedFile | None) -> bool:
    if left is None or right is None:
        return left is None and right is None
    return (
        left.digest == right.digest
        and left.executable == right.executable
        and left.size == right.size
    )


def _render_conflict(
    repository: Repository,
    base_file: TrackedFile | None,
    current_file: TrackedFile | None,
    target_file: TrackedFile | None,
) -> str:
    ours = _decode_file(repository, current_file)
    base = _decode_file(repository, base_file)
    theirs = _decode_file(repository, target_file)
    return (
        "<<<<<<< current\n"
        f"{ours}"
        "||||||| base\n"
        f"{base}"
        "=======\n"
        f"{theirs}"
        ">>>>>>> target\n"
    )


def _decode_file(repository: Repository, file: TrackedFile | None) -> str:
    if file is None:
        return ""
    return repository.read_object("blobs", file.digest).decode("utf-8", errors="replace")


def _write_conflicts(repository: Repository, conflicts: tuple[ConflictFile, ...]) -> None:
    for conflict in conflicts:
        target = repository.root / Path(conflict.path)
        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_text(conflict.content, encoding="utf-8")


def _write_commit(
    repository: Repository,
    *,
    tree: Mapping[str, TrackedFile],
    parents: tuple[str, ...],
    message: str,
) -> str:
    tree_id = repository._store_tree(tree)
    record = CommitRecord(tree=tree_id, parents=parents, message=message)
    commit_id = repository.store_object("commits", serialize_commit(record))
    repository.write_branch(_current_branch(repository), commit_id)
    repository.write_index(IndexState())
    return commit_id


def _resolve_target_ref(repository: Repository, revision: str) -> str | None:
    try:
        commit_id = repository.read_branch(revision)
    except ValueError:
        return None
    if commit_id is not None or repository.layout.branch_path(revision).exists():
        return branch_ref(revision)
    return None


def _current_branch(repository: Repository) -> str:
    branch_name = repository.current_branch_name()
    if branch_name is None:
        raise RuntimeError("HEAD must point to a branch")
    return branch_name


def _ensure_operation_ready(repository: Repository) -> None:
    if repository.current_operation() is not None:
        raise ValueError("another operation is already in progress")
    if not repository.status().is_clean():
        raise ValueError("working tree must be clean before merge")

from __future__ import annotations

from dataclasses import replace
from pathlib import Path
from typing import Callable, TypeVar

from lit.merge_ops import MergeResult, merge_revision
from lit.rebase_ops import RebaseResult, rebase_onto
from lit.repository import CheckoutRecord, Repository
from lit_gui.backend import SnapshotFeedback, SnapshotSelections, build_snapshot
from lit_gui.contracts import RepositorySession, SessionSnapshot
from lit_gui.persistence import RecentRepositoriesStore

_T = TypeVar("_T")


class LitRepositorySession(RepositorySession):
    def __init__(
        self,
        root: Path | None = None,
        *,
        recent_store: RecentRepositoriesStore | None = None,
    ) -> None:
        self._recent_store = recent_store or RecentRepositoriesStore()
        self._root = self._resolve_root(root or Path.cwd())
        self._repository: Repository | None = self._reload_repository(self._root)
        self._recent_roots: tuple[Path, ...] = self._recent_store.load()
        self._selections = SnapshotSelections()
        self._feedback: SnapshotFeedback | None = None
        self._snapshot = self._rebuild_snapshot()

    def snapshot(self) -> SessionSnapshot:
        return self._snapshot

    def open_repository(self, root: Path) -> SessionSnapshot:
        self._root = self._resolve_root(root)
        validation_error = self._validate_open_root(self._root)
        if validation_error is not None:
            self._repository = None
            self._selections = SnapshotSelections()
            return self._rebuild_snapshot(
                feedback=SnapshotFeedback(level="error", message=validation_error)
            )

        self._repository = self._reload_repository(self._root)
        self._selections = SnapshotSelections()
        self._remember_recent(self._root, persist=True)
        if self._repository is None:
            return self._rebuild_snapshot(
                feedback=SnapshotFeedback(
                    level="info",
                    message=f"No .lit metadata detected at {self._root}.",
                )
            )
        return self._rebuild_snapshot(
            feedback=SnapshotFeedback(
                level="success",
                message=f"Opened lit repository at {self._root}.",
            )
        )

    def initialize_repository(self, root: Path) -> SessionSnapshot:
        self._root = self._resolve_root(root)
        validation_error = self._validate_initialize_root(self._root)
        if validation_error is not None:
            self._repository = None
            self._selections = SnapshotSelections()
            return self._rebuild_snapshot(
                feedback=SnapshotFeedback(level="error", message=validation_error)
            )

        already_initialized = (self._root / ".lit").is_dir()
        self._repository = Repository.create(self._root)
        self._selections = SnapshotSelections()
        self._remember_recent(self._root, persist=True)
        message = (
            f"Opened existing lit repository at {self._root}."
            if already_initialized
            else f"Initialized empty lit repository in {self._repository.layout.dot_lit}."
        )
        return self._rebuild_snapshot(feedback=SnapshotFeedback(level="success", message=message))

    def refresh(self) -> SessionSnapshot:
        self._repository = self._reload_repository(self._root)
        message = (
            f"Repository refreshed at {self._root}."
            if self._repository is not None
            else f"No .lit metadata detected at {self._root}."
        )
        level = "success" if self._repository is not None else "info"
        return self._rebuild_snapshot(feedback=SnapshotFeedback(level=level, message=message))

    def stage_paths(self, paths: tuple[str, ...]) -> SessionSnapshot:
        return self._run_repository_action(
            lambda repository: repository.stage(paths),
            on_success=lambda staged: SnapshotFeedback(
                level="success",
                message=f"staged {len(staged)} path(s)",
            ),
        )

    def restore_paths(self, paths: tuple[str, ...], *, source: str | None = None) -> SessionSnapshot:
        source_label = source or "HEAD"
        return self._run_repository_action(
            lambda repository: repository.restore(paths, source=source),
            on_success=lambda restored: SnapshotFeedback(
                level="success",
                message=f"restored {len(restored)} path(s) from {source_label}",
            ),
        )

    def commit(self, message: str) -> SessionSnapshot:
        return self._run_repository_action(
            lambda repository: repository.commit(message),
            on_success=lambda commit_id: self._commit_feedback(commit_id, message),
            update_selections=lambda commit_id: replace(self._selections, commit_id=commit_id),
        )

    def select_change(self, path: str) -> SessionSnapshot:
        self._selections = replace(self._selections, change_path=path)
        return self._rebuild_snapshot()

    def select_commit(self, commit_id: str) -> SessionSnapshot:
        self._selections = replace(self._selections, commit_id=commit_id, commit_path=None)
        return self._rebuild_snapshot()

    def select_commit_path(self, path: str | None) -> SessionSnapshot:
        self._selections = replace(self._selections, commit_path=path)
        return self._rebuild_snapshot()

    def create_branch(self, name: str, *, start_point: str | None = "HEAD") -> SessionSnapshot:
        return self._run_repository_action(
            lambda repository: repository.create_branch(name, start_point=start_point),
            on_success=lambda branch: SnapshotFeedback(
                level="success",
                message=f"{branch.name} -> {branch.commit_id[:12] if branch.commit_id else 'unborn'}",
            ),
            update_selections=lambda branch: replace(self._selections, branch_name=branch.name),
        )

    def select_branch(self, branch_name: str) -> SessionSnapshot:
        self._selections = replace(self._selections, branch_name=branch_name)
        return self._rebuild_snapshot()

    def checkout(self, revision: str) -> SessionSnapshot:
        return self._run_repository_action(
            lambda repository: repository.checkout(revision),
            on_success=self._checkout_feedback,
            update_selections=self._checkout_selections,
        )

    def merge(self, revision: str) -> SessionSnapshot:
        return self._run_repository_action(
            lambda repository: merge_revision(repository, revision),
            on_success=self._merge_feedback,
            update_selections=self._merge_selections,
        )

    def abort_merge(self) -> SessionSnapshot:
        def abort(repository: Repository) -> str:
            state = repository.read_merge_state()
            if state is None:
                raise ValueError("No merge in progress.")
            repository.apply_commit(
                state.current_commit,
                baseline_commit=repository.current_commit_id(),
            )
            repository.clear_merge()
            return state.current_commit

        return self._run_repository_action(
            abort,
            on_success=lambda _: SnapshotFeedback(level="success", message="Merge state cleared."),
            update_selections=lambda commit_id: replace(
                self._selections,
                change_path=None,
                commit_id=commit_id,
            ),
        )

    def rebase(self, revision: str) -> SessionSnapshot:
        return self._run_repository_action(
            lambda repository: rebase_onto(repository, revision),
            on_success=self._rebase_feedback,
            update_selections=self._rebase_selections,
        )

    def abort_rebase(self) -> SessionSnapshot:
        def abort(repository: Repository) -> str:
            state = repository.read_rebase_state()
            if state is None:
                raise ValueError("No rebase in progress.")
            branch_name = repository.current_branch_name()
            if branch_name is not None:
                repository.write_branch(branch_name, state.original_head)
            repository.apply_commit(
                state.original_head,
                baseline_commit=repository.current_commit_id(),
            )
            repository.clear_rebase()
            return state.original_head

        return self._run_repository_action(
            abort,
            on_success=lambda _: SnapshotFeedback(level="success", message="Rebase state cleared."),
            update_selections=lambda commit_id: replace(
                self._selections,
                change_path=None,
                commit_id=commit_id,
            ),
        )

    def select_file(self, path: str) -> SessionSnapshot:
        self._selections = replace(self._selections, file_path=path)
        return self._rebuild_snapshot()

    def _run_repository_action(
        self,
        operation: Callable[[Repository], _T],
        *,
        on_success: Callable[[_T], SnapshotFeedback],
        update_selections: Callable[[_T], SnapshotSelections] | None = None,
    ) -> SessionSnapshot:
        repository = self._repository
        if repository is None:
            return self._rebuild_snapshot(
                feedback=SnapshotFeedback(
                    level="error",
                    message="Open or initialize a repository first.",
                )
            )

        try:
            result = operation(repository)
        except (FileNotFoundError, RuntimeError, ValueError) as error:
            self._repository = self._reload_repository(self._root)
            return self._rebuild_snapshot(
                feedback=SnapshotFeedback(level="error", message=str(error))
            )

        if update_selections is not None:
            self._selections = update_selections(result)
        self._repository = self._reload_repository(self._root)
        return self._rebuild_snapshot(feedback=on_success(result))

    def _rebuild_snapshot(self, *, feedback: SnapshotFeedback | None = None) -> SessionSnapshot:
        if feedback is not None:
            self._feedback = feedback
        self._snapshot, self._selections = build_snapshot(
            root=self._root,
            repository=self._repository,
            recent_roots=self._recent_roots,
            selections=self._selections,
            feedback=self._feedback,
        )
        return self._snapshot

    def _remember_recent(self, root: Path, *, persist: bool = False) -> None:
        ordered = [root]
        ordered.extend(existing for existing in self._recent_roots if existing != root)
        self._recent_roots = tuple(ordered[:5])
        if persist:
            self._recent_store.save(self._recent_roots)

    def _reload_repository(self, root: Path) -> Repository | None:
        try:
            return Repository.open(root)
        except FileNotFoundError:
            return None

    def _resolve_root(self, root: Path) -> Path:
        return Path(root).expanduser().resolve()

    def _validate_open_root(self, root: Path) -> str | None:
        if not root.exists():
            return f"Folder not found: {root}."
        if not root.is_dir():
            return f"Path is not a folder: {root}."
        return None

    def _validate_initialize_root(self, root: Path) -> str | None:
        if root.exists() and not root.is_dir():
            return f"Path is not a folder: {root}."
        return None

    def _commit_feedback(self, commit_id: str, message: str) -> SnapshotFeedback:
        branch_name = self._repository.current_branch_name() if self._repository is not None else None
        label = branch_name or "detached"
        return SnapshotFeedback(
            level="success",
            message=f"[{label} {commit_id[:12]}] {message}",
        )

    def _checkout_feedback(self, result: CheckoutRecord) -> SnapshotFeedback:
        if result.branch_name is not None:
            return SnapshotFeedback(
                level="success",
                message=f"switched to branch {result.branch_name}",
            )
        target = "unborn" if result.commit_id is None else result.commit_id[:12]
        return SnapshotFeedback(level="success", message=f"detached HEAD at {target}")

    def _checkout_selections(self, result: CheckoutRecord) -> SnapshotSelections:
        return replace(
            self._selections,
            branch_name=result.branch_name,
            commit_id=result.commit_id,
            change_path=None,
        )

    def _merge_selections(self, result: MergeResult) -> SnapshotSelections:
        branch_name = self._repository.current_branch_name() if self._repository is not None else self._selections.branch_name
        return replace(
            self._selections,
            branch_name=branch_name,
            change_path=result.conflicts[0] if result.conflicts else None,
            file_path=result.conflicts[0] if result.conflicts else self._selections.file_path,
            commit_id=result.commit_id if result.commit_id is not None else self._selections.commit_id,
        )

    def _rebase_selections(self, result: RebaseResult) -> SnapshotSelections:
        branch_name = self._repository.current_branch_name() if self._repository is not None else self._selections.branch_name
        return replace(
            self._selections,
            branch_name=branch_name,
            change_path=result.conflicts[0] if result.conflicts else None,
            file_path=result.conflicts[0] if result.conflicts else self._selections.file_path,
            commit_id=result.commit_id if result.commit_id is not None else self._selections.commit_id,
        )

    def _merge_feedback(self, result: MergeResult) -> SnapshotFeedback:
        level = "info" if result.status in {"conflict", "noop"} else "success"
        return SnapshotFeedback(level=level, message=result.message)

    def _rebase_feedback(self, result: RebaseResult) -> SnapshotFeedback:
        level = "info" if result.status in {"conflict", "noop"} else "success"
        return SnapshotFeedback(level=level, message=result.message)

from __future__ import annotations

from abc import ABC, abstractmethod
from dataclasses import dataclass
from enum import StrEnum
from pathlib import Path
from typing import Literal


class NavigationTarget(StrEnum):
    HOME = "home"
    CHANGES = "changes"
    HISTORY = "history"
    BRANCHES = "branches"
    FILES = "files"


VIEW_ORDER: tuple[NavigationTarget, ...] = (
    NavigationTarget.HOME,
    NavigationTarget.CHANGES,
    NavigationTarget.HISTORY,
    NavigationTarget.BRANCHES,
    NavigationTarget.FILES,
)


class DetailSlotId(StrEnum):
    SELECTION = "selection"
    METADATA = "metadata"
    GUIDANCE = "guidance"


@dataclass(frozen=True, slots=True)
class OperationSummary:
    kind: Literal["merge", "rebase"]
    summary: str
    conflicts: tuple[str, ...] = ()


@dataclass(frozen=True, slots=True)
class RepositoryDescriptor:
    name: str
    root: Path | None = None
    current_branch: str | None = None
    head_commit: str | None = None
    status_text: str = ""
    is_lit_repository: bool = False
    operation: OperationSummary | None = None
    attention: str = ""


@dataclass(frozen=True, slots=True)
class RecentRepository:
    name: str
    root: Path
    summary: str = ""
    is_lit_repository: bool = False


@dataclass(frozen=True, slots=True)
class SummaryItem:
    label: str
    value: str


@dataclass(frozen=True, slots=True)
class DetailSlotState:
    slot_id: DetailSlotId
    title: str
    body: str


@dataclass(frozen=True, slots=True)
class DetailPaneState:
    selection: DetailSlotState
    metadata: DetailSlotState
    guidance: DetailSlotState

    @classmethod
    def placeholder(
        cls,
        *,
        selection_title: str,
        selection_body: str,
